/// Diff two commits (`base...head` when threeDot).
fn diff_commits(
    repo_path: String,
    base: String,
    head: String,
    three_dot: bool,
) -> Result<magnus::RArray, Error> {
    let out =
        <crate::core_impl::GitImpl as GitCore>::diff_commits(repo_path, base, head, three_dot)
            .map_err(rberr)?;
    let ruby = Ruby::get().map_err(|e| rberr(e))?;
    let ary = ruby.ary_new();
    for v in out {
        ary.push(v)?;
    }
    Ok(ary)
}

