/// Poll-based stream from `Entl.changes` — `.next` returns the next item or nil.
#[magnus::wrap(class = "Entl::Changes", free_immediately, size)]
pub struct Changes {
    stream: Box<dyn PollStream<ChangeBatch>>,
}
impl Changes {
    fn next(&self) -> Option<ChangeBatch> {
        loop {
            match self.stream.poll(Duration::from_millis(500)) {
                Poll::Item(v) => return Some(v),
                Poll::Idle => continue,
                Poll::Closed => return None, // nil ends iteration
            }
        }
    }
}

