/// An open entl database. Heavy ops are unary (off-thread in async hosts).
#[magnus::wrap(class = "Entl", free_immediately, size)]
pub struct Entl {
    core: Arc<crate::core_impl::EntlImpl>,
}

impl Entl {
    /// Open (or create) the .duckdb at `dbPath` and apply the schema.
    fn new(db_path: String) -> Result<Self, Error> {
        Ok(Self {
            core: Arc::new(<crate::core_impl::EntlImpl as EntlCore>::open(db_path).map_err(rberr)?),
        })
    }
    /// Load git history from `repoPath` (one-way, incremental).
    fn load_git(&self, repo_path: String) -> Result<GitStats, Error> {
        self.core.load_git(repo_path).map_err(rberr)
    }
    /// Load GitHub data (events/PRs/issues/Actions). Needs a token.
    fn load_github(&self, repo_path: String) -> Result<GithubStats, Error> {
        self.core.load_github(repo_path).map_err(rberr)
    }
    /// Run a SQL query; JSON rows back.
    fn query(&self, sql: String) -> Result<String, Error> {
        self.core.query(sql).map_err(rberr)
    }
    /// Run a SQL query; the result as one Arrow IPC stream (schema + all batches) —
    /// the dataframe on-ramp (pyarrow → pandas/polars, apache-arrow JS, red-arrow).
    fn query_arrow(&self, sql: String) -> Result<Bytes, Error> {
        self.core.query_arrow(sql).map_err(rberr)
    }
    /// Pull `repoPath` and sync it into a target store, in one call.
    fn sink(&self, args: &[magnus::Value]) -> Result<SinkStats, Error> {
        let a = magnus::scan_args::scan_args::<
            (String, String),
            (
                Option<String>,
                Option<bool>,
                Option<Vec<String>>,
                Option<Vec<String>>,
                Option<String>,
                Option<bool>,
            ),
            (),
            (),
            (),
            (),
        >(args)?;
        let (repo_path, target) = a.required;
        let (path, github, tables, exclude, schema, objects) = a.optional;
        let target = SinkTarget::parse(&target).map_err(rberr)?;
        let sink_options_arg = SinkOptions {
            target,
            path,
            github,
            tables,
            exclude,
            schema,
            objects,
            rename: None,
        };

        self.core.sink(repo_path, sink_options_arg).map_err(rberr)
    }
    /// Read a store back into canonical rows (JSON; oids hex, timestamps RFC3339).
    fn extract(&self, args: &[magnus::Value]) -> Result<String, Error> {
        let a = magnus::scan_args::scan_args::<
            (String, String),
            (Option<Vec<String>>, Option<String>),
            (),
            (),
            (),
            (),
        >(args)?;
        let (source, path) = a.required;
        let (tables, schema) = a.optional;
        let extract_options_arg = ExtractOptions {
            source,
            path,
            tables,
            schema,
        };

        self.core.extract(extract_options_arg).map_err(rberr)
    }
    /// Stream the change batches from one pull (the stream plane).
    fn changes(&self, args: &[magnus::Value]) -> Result<Changes, Error> {
        let a = magnus::scan_args::scan_args::<
            (String,),
            (Option<bool>, Option<bool>),
            (),
            (),
            (),
            (),
        >(args)?;
        let (repo_path,) = a.required;
        let (github, objects) = a.optional;
        let changes_options_arg = ChangesOptions { github, objects };

        Ok(Changes {
            stream: self
                .core
                .changes(repo_path, Some(changes_options_arg))
                .map_err(rberr)?,
        })
    }
    /// Backfill this store into a driver target: stream {sql, params} for the host to execute.
    fn driver_plan(&self, args: &[magnus::Value]) -> Result<DriverPlan, Error> {
        let a = magnus::scan_args::scan_args::<
            (),
            (Option<Vec<String>>, Option<Vec<String>>, Option<String>),
            (),
            (),
            (),
            (),
        >(args)?;
        let (tables, exclude, schema) = a.optional;
        let driver_plan_options_arg = DriverPlanOptions {
            tables,
            exclude,
            schema,
            rename: None,
        };

        Ok(DriverPlan {
            stream: self
                .core
                .driver_plan(Some(driver_plan_options_arg))
                .map_err(rberr)?,
        })
    }
    /// Reconstruct a git repo from a store (needs objects: true at sink time). Returns commits rebuilt.
    fn rebuild(&self, args: &[magnus::Value]) -> Result<i64, Error> {
        let a = magnus::scan_args::scan_args::<
            (String, String, String),
            (Option<String>,),
            (),
            (),
            (),
            (),
        >(args)?;
        let (source, dest, out) = a.required;
        let (schema,) = a.optional;
        let rebuild_options_arg = RebuildOptions {
            source,
            dest,
            out,
            schema,
        };

        self.core.rebuild(rebuild_options_arg).map_err(rberr)
    }
    // @manual: watch — hand-written in lib.rs if this binding offers it.
}

